import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"ゲームの起動","description":"さまざまな起動プロファイルを活用して、実際のゲーム環境で Mod を起動およびデバッグする方法を学びましょう。","frontmatter":{"title":"ゲームの起動","description":"さまざまな起動プロファイルを活用して、実際のゲーム環境で Mod を起動およびデバッグする方法を学びましょう。","authors":["IMB11","Tenneb22"],"files":[]},"headers":[],"relativePath":"ja_jp/1.21.4/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.4/translated/ja_jp/develop/getting-started/launching-the-game.md","lastUpdated":1760721669000}`);var c={name:`ja_jp/1.21.4/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">ゲームの起動 <a class="header-anchor" href="#h1" aria-label="Permalink to “ゲームの起動”">​</a></h1><p>Fabric Loom は、実際のゲーム環境で Mod を起動およびデバッグするのに役立つさまざまな起動プロファイルを提供します。 このガイドでは、さまざまな起動プロファイルと、それらを使用して Mod をデバッグおよびテストする方法について説明します。 このガイドでは、さまざまな起動プロファイルと、それらを使用して Mod をデバッグおよびテストする方法について説明します。</p><h2 id="launch-profiles" tabindex="-1">起動プロファイル <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “起動プロファイル”">​</a></h2><p>IntelliJ IDEA を使用している場合は、ウィンドウの右上に起動プロファイルが表示されます。 ドロップダウンメニューをクリックすると、利用可能な起動プロファイルの一覧が表示されます。 ドロップダウンメニューをクリックすると、利用可能な起動プロファイルの一覧が表示されます。</p><p>クライアントプロファイルとサーバープロファイルがあり、通常モードで実行するかデバッグ モードで実行するかを選択できるオプションがあります：</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Launch Profiles" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Gradle タスク <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Gradle タスク”">​</a></h2><p>コマンドラインを使用している場合は、次の Gradle コマンドを使用してゲームを開始できます：</p><ul><li><code>./gradlew runClient</code> - クライアントモードでゲームを起動。</li><li><code>./gradlew runServer</code> - サーバーモードでゲームを起動。</li></ul><p>この方法の唯一の問題は、コードを簡単にデバッグできないことです。 この方法の唯一の問題は、コードを簡単にデバッグできないことです。 コードをデバッグしたい場合は、IntelliJ IDEA の起動プロファイルを使用するか、IDE の Gradle 統合を介して起動プロファイルを使用する必要があります。</p><h2 id="hotswapping-classes" tabindex="-1">クラスのホットスワップ <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “クラスのホットスワップ”">​</a></h2><p>ゲームをデバッグモードで実行すると、ゲームを再起動せずにクラスをホットスワップできます。 これは、コードの変更をすばやくテストするのに役立ちます。 これは、コードの変更をすばやくテストするのに役立ちます。</p><p>ただし、まだかなり制限があります：</p><ul><li>メソッドを追加または削除することはできません</li><li>メソッドのパラメーターを変更することはできません</li><li>フィールドを追加または削除することはできません</li></ul><p>ただし、 <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a> を使用すると、ほとんどの制限を回避でき、クラスやメソッドを追加または削除することもできます。 これにより、ゲームを再起動せずにほとんどの変更を行えます。 これにより、ゲームを再起動せずにほとんどの変更を行えます。</p><p>Minecraft 実行構成の VM 引数に以下を追加することを忘れないでください：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Mixin のホットスワップ <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Mixin のホットスワップ”">​</a></h2><p>Mixin を使用している場合、ゲームを再起動せずに Mixin をホットスワップできます。 これは、Mixin の変更をすばやくテストするのに役立ちます。 これは、Mixin の変更をすばやくテストするのに役立ちます。</p><p>ただし、これをするには、Mixin Java エージェントをインストールする必要があります。</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Mixin ライブラリの Jar ファイルを見つける <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Mixin ライブラリの Jar ファイルを見つける”">​</a></h3><p>IntelliJ IDEA では、プロジェクトセクションの外部ライブラリセクションで Mixin ライブラリの Jar ファイルを見つけることができます：</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin Library" loading="lazy"></p><p>次のステップでは、jar の絶対パスをコピーする必要があります。</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. <code>-javaagent</code> を VM 引数に追加 <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. -javaagent を VM 引数に追加”">​</a></h3><p>Minecraft Client または Minecraft Server の実行構成で、VM 引数オプションに以下を追加します：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;ここに Mixin ライブラリの Jar ファイルのパスを入力&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="VM Arguments Screenshot" loading="lazy"></p><p>これで、デバッグ中はゲームの再起動なしに Mixin メソッドの変更を加えられるようになりました。</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};